      `oauth:refresh:${refreshToken}`,
      REFRESH_TOKEN_TTL_SECONDS,
      JSON.stringify({
        client_id: req.client.client_id,
        user_id: authz.user_id,
        scope: authz.scope,
        iat: issuedAt,
        exp: issuedAt + REFRESH_TOKEN_TTL_SECONDS
      })
