app.post('/introspect', requireClient, async (req, res) => {
  const token = req.body.token;
  if (!token) {
    return res.status(400).json({ error: 'invalid_request' });
  }

  const rawAccess = await redis.get(`oauth:access:${token}`);
  if (rawAccess) {
    const data = JSON.parse(rawAccess);
    return res.json({
      active: true,
      token_type: 'access_token',
      client_id: data.client_id,
      username: data.user_id,
      scope: data.scope.join(' '),
      exp: data.exp,
      iat: data.iat
    });
  }

  const rawRefresh = await redis.get(`oauth:refresh:${token}`);
  if (rawRefresh) {
    const data = JSON.parse(rawRefresh);
    return res.json({
      active: true,
      token_type: 'refresh_token',
      client_id: data.client_id,
      username: data.user_id,
      scope: data.scope.join(' '),
      exp: data.exp,
      iat: data.iat
    });
  }

  return res.json({ active: false });
});

app.post('/revoke', requireClient, async (req, res) => {
  const token = req.body.token;
  if (!token) {
    return res.status(200).send();
  }

  await redis.del(`oauth:access:${token}`);
  await redis.del(`oauth:refresh:${token}`);
  return res.status(200).send();
});

